    pf.space_after = Pt(after)
    pf.line_spacing = line
    pf.line_spacing_rule = WD_LINE_SPACING.MULTIPLE if line != 1.0 else WD_LINE_SPACING.SINGLE
    if indent_left is not None:
        pf.left_indent = Inches(indent_left)
    if hanging is not None:
        pf.first_line_indent = Inches(hanging)

def set_runs(p, size, name='Calibri'):
    for r in p.runs:
        if r.font.size is None or True:
            r.font.size = Pt(size)
        r.font.name = name

# Body paragraphs (not in tables): 10pt, tight
