    elif sn in ('Title',):
        fmt_para(p, 0, 4, 1.0); set_runs(p, 15)
    else:
        # body / compact / block text / first paragraph
        after = 1 if sn == 'Compact' else 4
        fmt_para(p, 0, after, 1.04)
        set_runs(p, 10)
        # reduce list indentation for compact/list items
        if sn == 'Compact':
            pf = p.paragraph_format
            if pf.left_indent and pf.left_indent.inches > 0.5:
                pf.left_indent = Inches(0.3)

# Table cells: 8.5pt, zero spacing
