from docx import Document
from docx.oxml.ns import qn

doc = Document('output/governance-diligence-memo.docx')

# 1) Remove keep_with_next from ALL paragraphs (prevents heading-orphan whitespace)
for p in doc.paragraphs:
    p.paragraph_format.keep_with_next = False
    p.paragraph_format.keep_together = False

# 2) Remove cantSplit from all table rows so tables can break across pages
for tbl in doc.tables:
    for row in tbl.rows:
        trPr = row._tr.trPr
        if trPr is not None:
            for cs in trPr.findall(qn('w:cantSplit')):
                trPr.remove(cs)
            # also remove tblHeader (repeat header row) if causing issues - keep it actually, it's fine
    # allow the table to break: ensure no "keep with next" on table
    tblPr = tbl._tbl.tblPr

# 3) Also clear keep_with_next on paragraphs inside table cells
for tbl in doc.tables:
    for row in tbl.rows:
        for cell in row.cells:
            for p in cell.paragraphs:
                p.paragraph_format.keep_with_next = False
                p.paragraph_format.keep_together = False

doc.save('output/governance-diligence-memo.docx')
print('breaks fixed')
